import React, { useState } from 'react'
import { useQuery, useAction, getMyTeams, createTeam } from 'wasp/client/operations'
import { Link } from 'react-router-dom'
import { logout } from 'wasp/client/auth'

export const DashboardPage = ({ user }: { user: any }) => {
  const { data: teams, isLoading, error } = useQuery(getMyTeams)
  const createTeamAction = useAction(createTeam)
  const [newTeamName, setNewTeamName] = useState('')

  const handleCreateTeam = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!newTeamName) return
    try {
      await createTeamAction({ name: newTeamName })
      setNewTeamName('')
    } catch (err: any) {
      window.alert('Error creating team: ' + err.message)
    }
  }

  if (isLoading) return 'Loading...'
  if (error) return 'Error: ' + error.message

  return (
    <div style={{ padding: '20px' }}>
      <header style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <h1>Dashboard</h1>
        <div>
          <span>Welcome, {user.fullName || user.username}! </span>
          <button onClick={logout}>Logout</button>
        </div>
      </header>

      <section>
        <h2>Create a New Team</h2>
        <form onSubmit={handleCreateTeam}>
          <input
            type="text"
            placeholder="Team Name"
            value={newTeamName}
            onChange={(e) => setNewTeamName(e.target.value)}
          />
          <button type="submit">Create Team</button>
        </form>
      </section>

      <section style={{ marginTop: '20px' }}>
        <h2>My Teams</h2>
        {teams && teams.length === 0 ? (
          <p>You don't belong to any teams yet.</p>
        ) : (
          <ul>
            {teams?.map((team: any) => (
              <li key={team.id}>
                <Link to={`/team/${team.id}`}>{team.name}</Link> ({team.members.length} members)
              </li>
            ))}
          </ul>
        )}
      </section>
    </div>
  )
}

