import React, { useState } from 'react'
import { useQuery, useAction, getTeamTasks, createTask } from 'wasp/client/operations'
import { useParams, Link } from 'react-router-dom'

export const TeamPage = () => {
  const { id } = useParams()
  const teamId = parseInt(id!)

  const { data: tasks, isLoading, error } = useQuery(getTeamTasks, { teamId })
  const createTaskAction = useAction(createTask)
  const [newTaskDescription, setNewTaskDescription] = useState('')

  const handleCreateTask = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!newTaskDescription) return
    try {
      await createTaskAction({ description: newTaskDescription, teamId })
      setNewTaskDescription('')
    } catch (err: any) {
      window.alert('Error creating task: ' + err.message)
    }
  }

  if (isLoading) return 'Loading...'
  if (error) return (
    <div>
      <p>Error: {error.message}</p>
      <Link to="/">Back to Dashboard</Link>
    </div>
  )

  return (
    <div style={{ padding: '20px' }}>
      <Link to="/">← Back to Dashboard</Link>
      <h1>Team Tasks</h1>

      <section>
        <h2>Add a New Task</h2>
        <form onSubmit={handleCreateTask}>
          <input
            type="text"
            placeholder="Task Description"
            value={newTaskDescription}
